  1→"use client";
  2→
  3→import Link from "next/link";
  4→import { useParams, useRouter } from "next/navigation";
  5→import { useEffect, useLayoutEffect, useMemo, useRef, useState } from "react";
  6→import {
  7→  sellerApi,
  8→  type SellerOrder,
  9→  type SellerOffering,
 10→  type SellerPayoutSummary,
 11→  type SellerPickupLocation,
 12→  type SellerPickupWindow,
 13→  type SellerProduct,
 14→  type SellerSubscriptionPlan,
 15→} from "@/lib/seller-api";
 16→import { session } from "@/lib/session";
 17→import { QrCode } from "@/components/qr-code";
 18→import { useToast } from "@/components/toast";
 19→import { formatMoney, friendlyErrorMessage, parseApiError } from "@/lib/ui";
 20→import { StatusPill, PaymentPill } from "@/components/seller/status-pills";
 21→import { ConfirmDialog } from "@/components/confirm-dialog";
 22→
 23→type OrderFilter =
 24→  | "all"
 25→  | "placed"
 26→  | "ready"
 27→  | "picked_up"
 28→  | "no_show"
 29→  | "canceled";
 30→
 31→function formatWindowLabel(w: SellerPickupWindow): string {
 32→  const start = new Date(w.start_at);
 33→  const end = new Date(w.end_at);
 34→  if (Number.isNaN(start.getTime()) || Number.isNaN(end.getTime())) {
 35→    return `Window (${w.status})`;
 36→  }
 37→  return `${start.toLocaleString()}–${end.toLocaleTimeString()} (${w.status})`;
 38→}
 39→
 40→export default function SellerStorePage() {
 41→  const params = useParams<{ storeId: string }>();
 42→  const storeId = params.storeId;
 43→  const router = useRouter();
 44→  const { showToast, clearToast } = useToast();
 45→
 46→  const [token, setToken] = useState<string | null>(null);
 47→  const [error, setError] = useState<string | null>(null);
 48→
 49→  const [, setLocations] = useState<SellerPickupLocation[] | null>(null);
 50→  const [windows, setWindows] = useState<SellerPickupWindow[] | null>(null);
 51→  const [, setProducts] = useState<SellerProduct[] | null>(null);
 52→  const [, setOfferings] = useState<SellerOffering[] | null>(null);
 53→  const [orders, setOrders] = useState<SellerOrder[] | null>(null);
 54→  const [payoutSummary, setPayoutSummary] = useState<SellerPayoutSummary | null>(
 55→    null,
 56→  );
 57→  const [plans, setPlans] = useState<SellerSubscriptionPlan[] | null>(null);
 58→
 59→  const [selectedWindowId, setSelectedWindowId] = useState<string>("");
 60→  const [orderFilter, setOrderFilter] = useState<OrderFilter>("all");
 61→  const [supportOpen, setSupportOpen] = useState(false);
 62→  const supportBtnRef = useRef<HTMLButtonElement | null>(null);
 63→  const supportPanelRef = useRef<HTMLDivElement | null>(null);
 64→  const [supportPos, setSupportPos] = useState<{ top: number; left: number } | null>(null);
 65→  const [pickupCodeByOrderId, setPickupCodeByOrderId] = useState<
 66→    Record<string, string>
 67→  >({});
 68→  const [generatingCycle, setGeneratingCycle] = useState(false);
 69→  const [busyOrderId, setBusyOrderId] = useState<string | null>(null);
 70→  const [togglingPlan, setTogglingPlan] = useState(false);
 71→  const [confirmAction, setConfirmAction] = useState<{
 72→    title: string;
 73→    message: string;
 74→    confirmLabel: string;
 75→    destructive: boolean;
 76→    action: () => void;
 77→  } | null>(null);
 78→
 79→  const selectedWindow = useMemo(() => {
 80→    if (!selectedWindowId) return null;
 81→    return (windows ?? []).find((w) => w.id === selectedWindowId) ?? null;
 82→  }, [windows, selectedWindowId]);
 83→
 84→  const filteredOrders = useMemo(() => {
 85→    if (!orders) return null;
 86→    if (orderFilter === "all") return orders;
 87→    return orders.filter((o) => o.status === orderFilter);
 88→  }, [orders, orderFilter]);
 89→
 90→  const orderCounts = useMemo(() => {
 91→    const base: Record<OrderFilter, number> = {
 92→      all: 0,
 93→      placed: 0,
 94→      ready: 0,
 95→      picked_up: 0,
 96→      no_show: 0,
 97→      canceled: 0,
 98→    };
 99→    if (!orders) return base;
100→    base.all = orders.length;
101→    for (const o of orders) {
102→      const k = o.status as OrderFilter;
103→      if (k in base) base[k] += 1;
104→    }
105→    return base;
106→  }, [orders]);
107→
108→  const siteOrigin = useMemo(() => {
109→    if (typeof window === "undefined") return "";
110→    return window.location.origin;
111→  }, []);
112→
113→  // Redirect to setup if no live plan
114→  useEffect(() => {
115→    if (plans !== null && !plans.some((p) => p.is_live)) {
116→      router.replace(`/seller/stores/${storeId}/setup`);
117→    }
118→  }, [plans, storeId, router]);
119→
120→  useEffect(() => {
121→    const t = session.getToken();
122→    if (!t) {
123→      router.replace("/seller/login");
124→      return;
125→    }
126→    setToken(t);
127→  }, [router]);
128→
129→  useLayoutEffect(() => {
130→    if (!supportOpen) return;
131→
132→    const update = () => {
133→      const btn = supportBtnRef.current;
134→      if (!btn) return;
135→      const rect = btn.getBoundingClientRect();
136→      const w = 288; // matches w-[18rem]
137→      const pad = 10;
138→      const left = Math.max(
139→        pad,
140→        Math.min(rect.right - w, window.innerWidth - w - pad),
141→      );
142→      const top = Math.min(rect.bottom + 10, window.innerHeight - 20);
143→      setSupportPos({ top, left });
144→    };
145→
146→    update();
147→    window.addEventListener("resize", update);
148→    window.addEventListener("scroll", update, true);
149→    return () => {
150→      window.removeEventListener("resize", update);
151→      window.removeEventListener("scroll", update, true);
152→    };
153→  }, [supportOpen]);
154→
155→  useEffect(() => {
156→    if (!supportOpen) return;
157→    const onDown = (e: MouseEvent) => {
158→      const t = e.target as Node | null;
159→      if (!t) return;
160→      if (supportBtnRef.current?.contains(t)) return;
161→      if (supportPanelRef.current?.contains(t)) return;
162→      setSupportOpen(false);
163→    };
164→    const onKey = (e: KeyboardEvent) => {
165→      if (e.key === "Escape") setSupportOpen(false);
166→    };
167→    window.addEventListener("mousedown", onDown);
168→    window.addEventListener("keydown", onKey);
169→    return () => {
170→      window.removeEventListener("mousedown", onDown);
171→      window.removeEventListener("keydown", onKey);
172→    };
173→  }, [supportOpen]);
174→
175→  async function refreshAll(t: string) {
176→    const [ls, ws, ps, sps] = await Promise.all([
177→      sellerApi.listPickupLocations(t, storeId),
178→      sellerApi.listPickupWindows(t, storeId),
179→      sellerApi.listProducts(t, storeId),
180→      sellerApi.listSubscriptionPlans(t, storeId),
181→    ]);
182→    setLocations(ls);
183→    setWindows(ws);
184→    setProducts(ps);
185→    setPlans(sps);
186→    setSelectedWindowId((prev) => {
187→      if (prev && ws.some((w) => w.id === prev)) return prev;
188→      return ws[0]?.id ?? "";
189→    });
190→  }
191→
192→  useEffect(() => {
193→    if (!token) return;
194→    setError(null);
195→    refreshAll(token).catch((e: unknown) => {
196→      const apiErr = parseApiError(e);
197→      if (apiErr && apiErr.status === 403) {
198→        showToast({ kind: "error", message: "You don\u2019t have access to that store." });
199→        router.replace("/seller");
200→        return;
201→      }
202→      if (apiErr && apiErr.status === 404) {
203→        showToast({ kind: "error", message: "Store not found." });
204→        router.replace("/seller");
205→        return;
206→      }
207→      setError(friendlyErrorMessage(e));
208→    });
209→    // eslint-disable-next-line react-hooks/exhaustive-deps
210→  }, [token, storeId]);
211→
212→  useEffect(() => {
213→    if (!token || !selectedWindowId) return;
214→    setError(null);
215→    sellerApi
216→      .listOfferings(token, storeId, selectedWindowId)
217→      .then(setOfferings)
218→      .catch((e: unknown) => setError(friendlyErrorMessage(e)));
219→  }, [token, storeId, selectedWindowId]);
220→
221→  useEffect(() => {
222→    if (!token || !selectedWindowId) return;
223→    setError(null);
224→    sellerApi
225→      .listOrders(token, storeId, selectedWindowId)
226→      .then(setOrders)
227→      .catch((e: unknown) => setError(friendlyErrorMessage(e)));
228→  }, [token, storeId, selectedWindowId]);
229→
230→  useEffect(() => {
231→    if (!token || !selectedWindowId) return;
232→    sellerApi
233→      .getPayoutSummary(token, storeId, selectedWindowId)
234→      .then(setPayoutSummary)
235→      .catch(() => setPayoutSummary(null));
236→  }, [token, storeId, selectedWindowId]);
237→
238→  async function generateNextCycle(planId: string) {
239→    if (!token) return;
240→    setError(null);
241→    clearToast();
242→    setGeneratingCycle(true);
243→    try {
244→      const res = await sellerApi.generateNextCycle(token, storeId, planId);
245→      await refreshAll(token);
246→      setSelectedWindowId(res.pickup_window_id);
247→      showToast({
248→        kind: "success",
249→        message: "Pickup cycle generated. You are now live.",
250→      });
251→    } catch (e: unknown) {
252→      setError(friendlyErrorMessage(e));
253→      showToast({ kind: "error", message: "Could not generate pickup cycle." });
254→    } finally {
255→      setGeneratingCycle(false);
256→    }
257→  }
258→
259→  function togglePlanActive(planId: string, currentlyActive: boolean) {
260→    if (!token) return;
261→    const action = currentlyActive ? "pause" : "resume";
262→    setConfirmAction({
263→      title: currentlyActive ? "Pause box?" : "Resume box?",
264→      message: currentlyActive
265→        ? "It will stop appearing for new buyers."
266→        : "It will be visible to buyers again.",
267→      confirmLabel: currentlyActive ? "Pause" : "Resume",
268→      destructive: currentlyActive,
269→      action: async () => {
270→        setTogglingPlan(true);
271→        setError(null);
272→        try {
273→          await sellerApi.updateSubscriptionPlan(token, storeId, planId, {
274→            is_active: !currentlyActive,
275→          });
276→          await refreshAll(token);
277→          showToast({
278→            kind: "success",
279→            message: action === "pause" ? "Box paused." : "Box resumed.",
280→          });
281→        } catch (e: unknown) {
282→          setError(friendlyErrorMessage(e));
283→          showToast({ kind: "error", message: `Could not ${action} box.` });
284→        } finally {
285→          setTogglingPlan(false);
286→        }
287→      },
288→    });
289→  }
290→
291→  async function setOrderStatus(
292→    orderId: string,
293→    status: "ready" | "canceled" | "no_show",
294→    opts?: { waive_fee?: boolean },
295→  ) {
296→    if (!token || !selectedWindowId) return;
297→    if (status === "canceled") {
298→      setConfirmAction({
299→        title: "Cancel order?",
300→        message: "This will release reserved inventory.",
301→        confirmLabel: "Cancel order",
302→        destructive: true,
303→        action: () => executeOrderStatus(orderId, status, opts),
304→      });
305→      return;
306→    }
307→    if (status === "no_show") {
308→      setConfirmAction({
309→        title: "Mark as no-show?",
310→        message: "This will release reserved inventory.",
311→        confirmLabel: "Mark no-show",
312→        destructive: true,
313→        action: () => executeOrderStatus(orderId, status, opts),
314→      });
315→      return;
316→    }
317→    executeOrderStatus(orderId, status, opts);
318→  }
319→
320→  async function executeOrderStatus(
321→    orderId: string,
322→    status: "ready" | "canceled" | "no_show",
323→    opts?: { waive_fee?: boolean },
324→  ) {
325→    if (!token || !selectedWindowId) return;
326→    setBusyOrderId(orderId);
327→    setError(null);
328→    try {
329→      await sellerApi.updateOrderStatus(token, storeId, orderId, status, opts);
330→      // Refresh both orders and offerings since inventory may have changed.
331→      const [os, ofs] = await Promise.all([
332→        sellerApi.listOrders(token, storeId, selectedWindowId),
333→        sellerApi.listOfferings(token, storeId, selectedWindowId),
334→      ]);
335→      setOrders(os);
336→      setOfferings(ofs);
337→      const labels: Record<string, string> = {
338→        ready: "Order marked ready.",
339→        canceled: "Order canceled.",
340→        no_show: "Marked as no-show.",
341→      };
342→      showToast({ kind: "success", message: labels[status] ?? "Order updated." });
343→    } catch (e: unknown) {
344→      setError(friendlyErrorMessage(e));
345→    } finally {
346→      setBusyOrderId(null);
347→    }
348→  }
349→
350→  async function confirmPickup(orderId: string) {
351→    if (!token || !selectedWindowId) return;
352→    const code = (pickupCodeByOrderId[orderId] ?? "").trim();
353→    if (!/^[0-9]{6}$/.test(code)) {
354→      setError("Pickup code must be 6 digits.");
355→      return;
356→    }
357→    setBusyOrderId(orderId);
358→    setError(null);
359→    try {
360→      await sellerApi.confirmPickup(token, storeId, orderId, code);
361→      // Refresh both orders and offerings since inventory may have changed.
362→      const [os, ofs] = await Promise.all([
363→        sellerApi.listOrders(token, storeId, selectedWindowId),
364→        sellerApi.listOfferings(token, storeId, selectedWindowId),
365→      ]);
366→      setOrders(os);
367→      setOfferings(ofs);
368→      setPickupCodeByOrderId((prev) => {
369→        const next = { ...prev };
370→        delete next[orderId];
371→        return next;
372→      });
373→      showToast({ kind: "success", message: "Pickup confirmed." });
374→    } catch (e: unknown) {
375→      setError(friendlyErrorMessage(e));
376→    } finally {
377→      setBusyOrderId(null);
378→    }
379→  }
380→
381→  return (
382→    <div className="grid gap-8">
383→      <header className="flex flex-wrap items-end justify-between gap-4">
384→        <div className="grid gap-2">
385→          <Link
386→            className="lr-btn lr-chip inline-flex w-fit items-center gap-2 px-4 py-2 text-sm font-medium text-[color:var(--lr-ink)]"
387→            href="/seller"
388→          >
389→            <span aria-hidden="true">←</span>
390→            Seller home
391→          </Link>
392→          <div>
393→            <h1 className="text-2xl font-semibold tracking-tight">Store</h1>
394→            <div className="mt-1 text-sm text-[color:var(--lr-muted)]">
395→              Manage your pickup windows, orders, and payouts.
396→            </div>
397→          </div>
398→        </div>
399→
400→        <div className="flex flex-wrap gap-2">
401→          <Link
402→            className="lr-btn lr-chip px-4 py-2 text-sm font-medium text-[color:var(--lr-ink)]"
403→            href={`/seller/stores/${storeId}/settings`}
404→          >
405→            Settings
406→          </Link>
407→          <button
408→            ref={supportBtnRef}
409→            type="button"
410→            className="lr-btn lr-chip px-4 py-2 text-sm font-medium text-[color:var(--lr-ink)]"
411→            aria-haspopup="dialog"
412→            aria-expanded={supportOpen}
413→            onClick={() => setSupportOpen((v) => !v)}
414→          >
415→            Support
416→          </button>
417→        </div>
418→      </header>
419→
420→      {supportOpen && supportPos ? (
421→        <div
422→          ref={supportPanelRef}
423→          role="dialog"
424→          aria-label="Support"
425→          className="fixed z-50 w-[18rem] rounded-2xl border border-[color:var(--lr-border)] bg-white/92 p-3 text-sm shadow-[0_22px_60px_rgba(38,28,10,0.16)] backdrop-blur"
426→          style={{ top: supportPos.top, left: supportPos.left }}
427→        >
428→          <div className="text-xs font-semibold uppercase tracking-wide text-[color:var(--lr-muted)]">
429→            Store ID
430→          </div>
431→          <div className="mt-2 flex items-center gap-2">
432→            <span className="lr-chip grow rounded-xl px-3 py-2 font-mono text-xs text-[color:var(--lr-ink)]">
433→              {storeId}
434→            </span>
435→            <button
436→              type="button"
437→              className="lr-btn lr-btn-primary px-3 py-2 text-xs font-semibold"
438→              onClick={() => {
439→                navigator.clipboard
440→                  .writeText(storeId)
441→                  .then(() => showToast({ kind: "success", message: "Store ID copied." }))
442→                  .catch(() =>
443→                    showToast({
444→                      kind: "error",
445→                      message: "Could not copy. Your browser may block clipboard access.",
446→                    }),
447→                  );
448→              }}
449→            >
450→              Copy
451→            </button>
452→          </div>
453→          <div className="mt-2 text-xs text-[color:var(--lr-muted)]">
454→            Only needed if you contact support.
455→          </div>
456→        </div>
457→      ) : null}
458→
459→      {error ? (
460→        <div className="lr-card border-rose-200 bg-rose-50/60 p-4 text-sm text-rose-900">
461→          {error}
462→        </div>
463→      ) : null}
464→
465→      <section className="lr-card lr-card-strong lr-animate sticky top-3 z-10 grid gap-3 p-4 md:p-5">
466→        <div className="flex flex-wrap items-center justify-between gap-3">
467→          <select
468→            className="lr-field px-3 py-2 text-sm"
469→            value={selectedWindowId}
470→            onChange={(e) => setSelectedWindowId(e.target.value)}
471→          >
472→            <option value="">Select a window…</option>
473→            {(windows ?? []).map((w) => (
474→              <option key={w.id} value={w.id}>
475→                {formatWindowLabel(w)}
476→              </option>
477→            ))}
478→          </select>
479→
480→          {selectedWindowId ? (
481→            <Link
482→              className="lr-btn lr-chip px-4 py-2 text-sm font-medium text-[color:var(--lr-ink)]"
483→              href={`/pickup-windows/${selectedWindowId}`}
484→              target="_blank"
485→              rel="noreferrer"
486→            >
487→              Buyer view
488→            </Link>
489→          ) : null}
490→        </div>
491→
492→        {selectedWindow ? (
493→          <>
494→            <div className="flex flex-wrap items-center justify-between gap-3">
495→              <div className="text-base font-semibold text-[color:var(--lr-ink)]">
496→                {(() => {
497→                  const start = new Date(selectedWindow.start_at);
498→                  const end = new Date(selectedWindow.end_at);
499→                  const now = new Date();
500→                  const label = start > now ? "Next pickup" : "Current pickup";
501→                  const day = start.toLocaleDateString(undefined, { weekday: "short", month: "short", day: "numeric" });
502→                  const startTime = start.toLocaleTimeString(undefined, { hour: "numeric", minute: "2-digit" });
503→                  const endTime = end.toLocaleTimeString(undefined, { hour: "numeric", minute: "2-digit" });
504→                  return `${label} · ${day} · ${startTime} – ${endTime}`;
505→                })()}
506→              </div>
507→              <StatusPill status={selectedWindow.status} />
508→            </div>
509→            <div className="flex flex-wrap items-center gap-2 text-sm text-[color:var(--lr-muted)]">
510→              <span>
511→                {selectedWindow.pickup_location.label ?? "Pickup"} ·{" "}
512→                {selectedWindow.pickup_location.city},{" "}
513→                {selectedWindow.pickup_location.region}
514→              </span>
515→              <span>·</span>
516→              <span>
517→                Orders close{" "}
518→                <span className="font-medium text-[color:var(--lr-ink)]">
519→                  {new Date(selectedWindow.cutoff_at).toLocaleDateString(undefined, { weekday: "short", month: "short", day: "numeric", hour: "numeric", minute: "2-digit" })}
520→                </span>
521→              </span>
522→            </div>
523→          </>
524→        ) : (
525→          <div className="text-sm text-[color:var(--lr-muted)]">
526→            Generate a box cycle to create a pickup window.
527→          </div>
528→        )}
529→      </section>
530→
531→      <div className="grid gap-8 lg:grid-cols-2">
532→        <section className="lr-card lr-animate grid gap-4 p-6">
533→          <div>
534→            <h2 className="text-base font-semibold">Subscription boxes</h2>
535→            <p className="mt-1 text-sm text-[color:var(--lr-muted)]">
536→              Curated seasonal boxes for recurring buyers. Print a farmstand QR
537→              to turn walk-up buyers into subscriptions.
538→            </p>
539→          </div>
540→
541→          {plans?.length ? (
542→            <ul className="grid gap-3">
543→              {plans.map((p) => (
544→                <li key={p.id} className="lr-chip rounded-2xl p-4">
545→                  <div className="flex flex-wrap items-start justify-between gap-4">
546→                    <div className="min-w-[240px]">
547→                      <div className="flex flex-wrap items-center gap-2">
548→                        <div className="font-semibold text-[color:var(--lr-ink)]">
549→                          {p.title}
550→                        </div>
551→                        <span className="lr-chip rounded-full px-3 py-1 text-xs font-semibold text-[color:var(--lr-muted)]">
552→                          {p.cadence}
553→                        </span>
554→                        {p.is_live ? (
555→                          <span className="lr-chip rounded-full px-3 py-1 text-xs font-semibold text-[color:var(--lr-leaf)]">
556→                            live
557→                          </span>
558→                        ) : (
559→                          <span className="lr-chip rounded-full px-3 py-1 text-xs font-semibold text-[color:var(--lr-clay)]">
560→                            draft
561→                          </span>
562→                        )}
563→                        {!p.is_active ? (
564→                          <span className="lr-chip rounded-full px-3 py-1 text-xs font-semibold text-[color:var(--lr-clay)]">
565→                            inactive
566→                          </span>
567→                        ) : null}
568→                      </div>
569→                      <div className="mt-1 text-sm text-[color:var(--lr-muted)]">
570→                        ${(p.price_cents / 100).toFixed(2)} · cap{" "}
571→                        {p.subscriber_limit} · next{" "}
572→                        {new Date(p.next_start_at).toLocaleString()}
573→                      </div>
574→                      <div className="mt-2 flex flex-wrap gap-2">
575→                        <Link
576→                          className="lr-btn lr-chip px-3 py-2 text-sm font-semibold text-[color:var(--lr-ink)]"
577→                          href={`/boxes/${p.id}`}
578→                          target="_blank"
579→                          rel="noreferrer"
580→                        >
581→                          {p.is_live ? "Buyer page" : "Preview buyer page"}
582→                        </Link>
583→                        <button
584→                          type="button"
585→                          className="lr-btn lr-btn-primary px-3 py-2 text-sm font-semibold"
586→                          onClick={() => generateNextCycle(p.id)}
587→                          disabled={generatingCycle}
588→                        >
589→                          {generatingCycle
590→                            ? "Generating…"
591→                            : p.is_live
592→                            ? "Generate next cycle"
593→                            : "Go live (generate first cycle)"}
594→                        </button>
595→                        <button
