640→                                  ? `${siteOrigin}/b/${p.id}`
641→                                  : `/b/${p.id}`;
642→                                navigator.clipboard
643→                                  .writeText(url)
644→                                  .then(() =>
645→                                    showToast({
646→                                      kind: "success",
