664→                          </div>
665→                        </>
666→                      ) : (
667→                        <div className="lr-chip grid gap-2 rounded-2xl p-4 text-right">
668→                          <div className="text-xs font-semibold uppercase tracking-wide text-[color:var(--lr-muted)]">
669→                            Farmstand QR
670→                          </div>
671→                          <div className="text-xs text-[color:var(--lr-muted)]">
672→                            Go live to enable the buyer QR.
673→                          </div>
674→                        </div>
675→                      )}
