876→                    {o.status === "ready" ? (
877→                      <>
878→                        <div className="grid gap-2">
879→                          <label className="grid gap-1">
880→                            <span className="text-xs font-semibold text-[color:var(--lr-muted)]">
881→                              Pickup code
